  process.stdout &&
  process.stdout.isTTY &&
  process.env.NO_COLOR === undefined;

const codes = {
  reset:   [0,   0],
  bold:    [1,  22],
  dim:     [2,  22],
  // Foreground
  black:   [30, 39],
  red:     [31, 39],
  green:   [32, 39],
  yellow:  [33, 39],
  blue:    [34, 39],
  magenta: [35, 39],
  cyan:    [36, 39],
  white:   [37, 39],
  gray:    [90, 39],
  // Bright
  brightRed:    [91, 39],
  brightGreen:  [92, 39],
  brightYellow: [93, 39],
  brightBlue:   [94, 39],
  brightCyan:   [96, 39],
};

function colorize(str, ...colorNames) {
  if (!isTTY()) return str;
  const open  = colorNames.map(n => codes[n] ? `${ESC}${codes[n][0]}m` : '').join('');
  const close = colorNames.map(n => codes[n] ? `${ESC}${codes[n][1]}m` : '').join('');
  return `${open}${str}${close}`;
}

